mapper.select:
SELECT order_num, work_order_id, plan_id, item_name, type, order_qty, current_qty, ename, worker_ename, order_start, work_status, total_count FROM ( SELECT inner_q.*, ROWNUM AS rn FROM ( SELECT wo.order_num, wo.order_id AS work_order_id, pp.plan_id, i.name AS item_name, wo.order_qty AS order_qty, wo.current_qty, e.ename, w.ename AS worker_ename, wo.order_start, wo.order_status AS work_status, i.type, f.facility_name, COUNT(*) OVER() AS total_count FROM work_order wo LEFT JOIN emp e ON wo.emp_num = e.emp_num LEFT JOIN emp w ON wo.worker_num = w.emp_num LEFT JOIN production_plan pp ON wo.plan_num = pp.plan_num LEFT JOIN item i ON pp.item_num = i.item_num LEFT JOIN ( SELECT item_num, facility_num FROM ( SELECT item_num, facility_num, ROW_NUMBER() OVER (PARTITION BY item_num ORDER BY flow) AS rn FROM process WHERE facility_num IS NOT NULL ) WHERE rn = 1 ) pr ON i.item_num = pr.item_num LEFT JOIN facility f ON pr.facility_num = f.facility_num
AND wo.order_start >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND wo.order_start <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND wo.order_status = #{work_status}
AND i.type = #{item_type}
AND pp.item_num = #{item_num}
AND (wo.order_id LIKE '%' || #{keyword} || '%' OR i.name LIKE '%' || #{keyword} || '%')
AND wo.order_status NOT IN ('완료', '취소')
ORDER BY
wo.order_start ASC wo.order_num DESC
) inner_q WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

mapper.update:
UPDATE stock
SET stock_qty = GREATEST(NVL(stock_qty, 0) + #{qty}, 0)
WHERE item_num = #{itemNum}

mapper.select:
SELECT plan_id, plan_num, plan_qty, item_name, plan_status, plan_start, plan_end, ename, total_count FROM ( SELECT inner_q.*, ROWNUM AS rn FROM ( SELECT pp.plan_id, pp.plan_num, pp.plan_qty, i.name AS item_name, CASE WHEN SYSDATE > pp.plan_end THEN '완료' WHEN SYSDATE >= pp.plan_start THEN '진행' ELSE '대기' END AS plan_status, pp.plan_start, pp.plan_end, e.ename, COUNT(*) OVER() AS total_count FROM production_plan pp LEFT JOIN item i ON pp.item_num = i.item_num LEFT JOIN emp e ON pp.emp_num = e.emp_num WHERE pp.plan_status NOT IN ('취소', '완료') AND (pp.plan_end IS NULL OR pp.plan_end >= TRUNC(SYSDATE))
AND (pp.plan_id LIKE '%' || #{keyword} || '%' OR i.name LIKE '%' || #{keyword} || '%')
ORDER BY pp.plan_num DESC ) inner_q WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

SELECT EMP_NUM, ENAME, DEPT_NAME, E_LEVEL, TEL, total_count FROM ( SELECT inner_q.*, ROWNUM AS rn FROM ( SELECT e.emp_num AS EMP_NUM, e.ename AS ENAME, d.dept_name AS DEPT_NAME, e.e_level AS E_LEVEL, e.tel AS TEL, COUNT(*) OVER() AS total_count FROM emp e LEFT JOIN dept d ON e.dept_num = d.dept_num WHERE e.dept_num IN (3, 5) AND e.status = 'Y'
AND (e.ename LIKE '%' || #{keyword} || '%' OR e.emp_num LIKE '%' || #{keyword} || '%')
ORDER BY e.dept_num, e.emp_num ) inner_q WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}
